+//! Hybrid Quantizer for Zell v2.0
+//!
+//! Creates hybrid Q2_K + outlier format for 30 TPS inference:
+//! 1. Converts outlier profile to CSR (Compressed Sparse Row) format
+//! 2. Q2_K requantization done via llama-quantize (external tool)
+//! 3. Outputs hybrid package: Q2_K base + CSR outliers
+//!
+//! Runtime formula: y = Q2K_matmul(x, W_q2k) + sparse_correction(x, outliers)
+//! The Q2_K approximation is fast (RAM-resident), outliers fix critical weights.
+
+const std = @import("std");
+const outlier_analyzer = @import("outlier_analyzer.zig");
+
+const log = std.log.scoped(.hybrid_quantizer);
+
+/// CSR (Compressed Sparse Row) format for efficient sparse matmul
+/// For a matrix M x N:
+/// - row_ptr[i] = start index in col_idx/values for row i
+/// - col_idx[row_ptr[i]..row_ptr[i+1]] = column indices for row i
+/// - values[row_ptr[i]..row_ptr[i+1]] = FP16 values for row i
+pub const CSRMatrix = struct {
+    rows: u32,
+    cols: u32,
+    nnz: u32, // Number of non-zeros (outliers)
+    row_ptr: []u32, // Length: rows + 1
+    col_idx: []u16, // Length: nnz (u16 sufficient for 14336 cols)
+    values: []f16, // Length: nnz
+
+    pub fn deinit(self: *CSRMatrix, allocator: std.mem.Allocator) void {
+        allocator.free(self.row_ptr);
+        allocator.free(self.col_idx);
+        allocator.free(self.values);
+    }
+
+    /// Size in bytes for Metal buffer allocation
+    pub fn sizeBytes(self: *const CSRMatrix) usize {
+        return (self.rows + 1) * @sizeOf(u32) + // row_ptr
+            self.nnz * @sizeOf(u16) + // col_idx
+            self.nnz * @sizeOf(f16); // values
+    }
+};
+
+/// Per-tensor CSR outlier data
+pub const TensorCSR = struct {
+    name: []const u8,
+    csr: CSRMatrix,
+
+    pub fn deinit(self: *TensorCSR, allocator: std.mem.Allocator) void {
+        allocator.free(self.name);
+        self.csr.deinit(allocator);
+    }
+};
+
+/// Hybrid format package
+pub const HybridPackage = struct {
+    /// Path to Q2_K quantized model
+    q2k_model_path: []const u8,
+    /// Path to CSR outlier data
+    csr_outliers_path: []const u8,
+    /// Total size in bytes
+    total_size_bytes: u64,
+    /// Estimated speedup factor
+    speedup_factor: f32,
+
+    pub fn deinit(self: *HybridPackage, allocator: std.mem.Allocator) void {
+        allocator.free(self.q2k_model_path);
+        allocator.free(self.csr_outliers_path);
+    }
+};
+
+pub const HybridQuantizer = struct {
+    allocator: std.mem.Allocator,
+
+    pub fn init(allocator: std.mem.Allocator) HybridQuantizer {
+        return .{ .allocator = allocator };
+    }
+
+    /// Convert outlier profile to CSR format
+    /// Input: flat indices into tensor (row-major)
+    /// Output: CSR format for sparse matmul
+    pub fn convertToCSR(
+        self: *HybridQuantizer,
+        outlier_indices: []const u32,
+        outlier_values: []const f16,
+        rows: u32,
+        cols: u32,
+    ) !CSRMatrix {
+        const nnz: u32 = @intCast(outlier_indices.len);
+
+        // Allocate CSR arrays
+        var row_ptr = try self.allocator.alloc(u32, rows + 1);
+        errdefer self.allocator.free(row_ptr);
+        var col_idx = try self.allocator.alloc(u16, nnz);
+        errdefer self.allocator.free(col_idx);
+        var values = try self.allocator.alloc(f16, nnz);
+        errdefer self.allocator.free(values);
+
+        // Count outliers per row
+        @memset(row_ptr, 0);
+        for (outlier_indices) |flat_idx| {
+            const row = flat_idx / cols;
+            if (row < rows) {
+                row_ptr[row + 1] += 1;
+            }
+        }
+
+        // Prefix sum to get row_ptr
+        for (1..rows + 1) |i| {
+            row_ptr[i] += row_ptr[i - 1];
+        }
+
+        // Fill col_idx and values (need temp array for insertion positions)
+        var insert_pos = try self.allocator.alloc(u32, rows);
+        defer self.allocator.free(insert_pos);
+        @memcpy(insert_pos, row_ptr[0..rows]);
+
+        for (outlier_indices, outlier_values) |flat_idx, val| {
+            const row = flat_idx / cols;
+            const col = flat_idx % cols;
+            if (row < rows) {
+                const pos = insert_pos[row];
+                col_idx[pos] = @intCast(col);
+                values[pos] = val;
+                insert_pos[row] += 1;
+            }
+        }
+
+        return CSRMatrix{
+            .rows = rows,
+            .cols = cols,
+            .nnz = nnz,
+            .row_ptr = row_ptr,
+            .col_idx = col_idx,
+            .values = values,
+        };
+    }
+
+    /// Create hybrid format from model and outlier profile
+    pub fn createHybrid(
+        self: *HybridQuantizer,
+        model_path: []const u8,
+        outlier_profile_path: []const u8,
+        output_dir: []const u8,
+    ) !HybridPackage {
+        log.info("Creating hybrid format...", .{});
+        log.info("  Model: {s}", .{model_path});
+        log.info("  Outliers: {s}", .{outlier_profile_path});
+
+        // Step 1: Load outlier profile
+        log.info("Loading outlier profile...", .{});
+        var profile = try outlier_analyzer.OutlierAnalyzer.loadProfile(
+            self.allocator,
+            outlier_profile_path,
+        );
+        defer profile.deinit(self.allocator);
+
+        log.info("  Loaded {d} tensors, {d} outliers", .{
+            profile.total_tensors,
+            profile.total_outliers,
+        });
+
+        // Step 2: Create Q2_K model path
+        const basename = std.fs.path.basename(model_path);
+        const stem = blk: {
+            if (std.mem.lastIndexOf(u8, basename, ".gguf")) |idx| {
+                break :blk basename[0..idx];
+            }
+            break :blk basename;
+        };
+
+        const q2k_filename = try std.fmt.allocPrint(
+            self.allocator,
+            "{s}-Q2_K.gguf",
+            .{stem},
+        );
+        defer self.allocator.free(q2k_filename);
+
+        const q2k_path = try std.fs.path.join(self.allocator, &.{ output_dir, q2k_filename });
+        errdefer self.allocator.free(q2k_path);
+
+        // Step 3: Check if Q2_K model exists (created externally via llama-quantize)
+        const q2k_exists = blk: {
+            std.fs.cwd().access(q2k_path, .{}) catch break :blk false;
+            break :blk true;
+        };
+
+        if (!q2k_exists) {
+            log.warn("Q2_K model not found: {s}", .{q2k_path});
+            log.warn("Create it using: llama-quantize {s} {s} Q2_K", .{ model_path, q2k_path });
+            log.warn("Continuing with CSR conversion only...", .{});
+        } else {
+            log.info("Q2_K model found: {s}", .{q2k_path});
+        }
+
+        // Step 4: Convert outlier profile to CSR format and save
+        const csr_filename = try std.fmt.allocPrint(
+            self.allocator,
+            "{s}-hybrid.csr",
+            .{stem},
+        );
+        defer self.allocator.free(csr_filename);
+
+        const csr_path = try std.fs.path.join(self.allocator, &.{ output_dir, csr_filename });
+        errdefer self.allocator.free(csr_path);
+
+        log.info("Converting to CSR format...", .{});
+        try self.saveCSRProfile(&profile, csr_path);
+
+        // Step 5: Calculate sizes
+        const q2k_size: u64 = if (q2k_exists) blk: {
+            const file = try std.fs.cwd().openFile(q2k_path, .{});
+            defer file.close();
+            const stat = try file.stat();
+            break :blk stat.size;
+        } else 0;
+
+        const csr_size = blk: {
+            const file = try std.fs.cwd().openFile(csr_path, .{});
+            defer file.close();
+            const stat = try file.stat();
+            break :blk stat.size;
+        };
+
+        const total_size = q2k_size + csr_size;
+
+        // Estimate sizes based on outlier profile if Q2_K doesn't exist
+        const estimated_q2k_size = profile.base_q2k_size_bytes;
+        const estimated_original_size = profile.original_size_bytes;
+
+        log.info("Hybrid package created:", .{});
+        if (q2k_exists) {
+            log.info("  Q2_K model: {s} ({d:.2} GB)", .{
+                q2k_path,
+                @as(f64, @floatFromInt(q2k_size)) / 1e9,
+            });
+        } else {
+            log.info("  Q2_K model: (not yet created, estimated {d:.2} GB)", .{
+                @as(f64, @floatFromInt(estimated_q2k_size)) / 1e9,
+            });
+        }
+        log.info("  CSR outliers: {s} ({d:.2} GB)", .{
+            csr_path,
+            @as(f64, @floatFromInt(csr_size)) / 1e9,
+        });
+        log.info("  Total: {d:.2} GB (vs {d:.2} GB original)", .{
+            @as(f64, @floatFromInt(if (q2k_exists) total_size else estimated_q2k_size + csr_size)) / 1e9,
+            @as(f64, @floatFromInt(estimated_original_size)) / 1e9,
+        });
+
+        // Speedup: RAM (200 GB/s) vs SSD (3 GB/s)
+        const effective_size = if (q2k_exists) total_size else estimated_q2k_size + csr_size;
+        const speedup: f32 = 200.0 / 3.0 * @as(f32, @floatFromInt(estimated_original_size)) /
+            @as(f32, @floatFromInt(effective_size));
+
+        log.info("  Estimated speedup: {d:.1}x", .{speedup});
+
+        return HybridPackage{
+            .q2k_model_path = q2k_path,
+            .csr_outliers_path = csr_path,
+            .total_size_bytes = effective_size,
+            .speedup_factor = speedup,
+        };
+    }
+
+    /// Save outlier profile as CSR binary format
+    fn saveCSRProfile(self: *HybridQuantizer, profile: *const outlier_analyzer.OutlierProfile, path: []const u8) !void {
+        const file = try std.fs.cwd().createFile(path, .{});
+        defer file.close();
+
+        // Magic + version
+        _ = try file.write("ZELL_CSR");
+        const version: u32 = 1;
+        _ = try file.write(std.mem.asBytes(&version));
+
+        // Tensor count
+        _ = try file.write(std.mem.asBytes(&profile.total_tensors));
+
+        // For each tensor, write CSR data
+        for (profile.tensor_stats) |stat| {
+            // Convert to CSR
+            var csr = try self.convertToCSR(
+                stat.outlier_indices,
+                stat.outlier_values,
+                stat.shape[0],
+                stat.shape[1],
+            );
+            defer csr.deinit(self.allocator);
+
+            // Name (length-prefixed)
+            const name_len: u16 = @intCast(stat.name.len);
+            _ = try file.write(std.mem.asBytes(&name_len));
+            _ = try file.write(stat.name);
+
+            // CSR metadata
+            _ = try file.write(std.mem.asBytes(&csr.rows));
+            _ = try file.write(std.mem.asBytes(&csr.cols));
+            _ = try file.write(std.mem.asBytes(&csr.nnz));
+
+            // CSR data
+            _ = try file.write(std.mem.sliceAsBytes(csr.row_ptr));
+            _ = try file.write(std.mem.sliceAsBytes(csr.col_idx));
+            _ = try file.write(std.mem.sliceAsBytes(csr.values));
+        }
+
+        log.info("Saved CSR profile to {s}", .{path});
+    }
+
+    /// Load CSR profile from binary file
+    pub fn loadCSRProfile(self: *HybridQuantizer, path: []const u8) ![]TensorCSR {
+        const file = try std.fs.cwd().openFile(path, .{});
+        defer file.close();
+
+        // Verify magic
+        var magic: [8]u8 = undefined;
+        _ = try file.readAll(&magic);
+        if (!std.mem.eql(u8, &magic, "ZELL_CSR")) {
+            return error.InvalidMagic;
+        }
+
+        var version: u32 = undefined;
+        _ = try file.readAll(std.mem.asBytes(&version));
+        if (version != 1) {
+            return error.UnsupportedVersion;
+        }
+
+        var tensor_count: u32 = undefined;
+        _ = try file.readAll(std.mem.asBytes(&tensor_count));
+
+        var tensors = try self.allocator.alloc(TensorCSR, tensor_count);
+        errdefer self.allocator.free(tensors);
+
+        for (0..tensor_count) |i| {
+            // Name
+            var name_len: u16 = undefined;
+            _ = try file.readAll(std.mem.asBytes(&name_len));
+            const name = try self.allocator.alloc(u8, name_len);
+            _ = try file.readAll(name);
+
+            // CSR metadata
+            var rows: u32 = undefined;
+            var cols: u32 = undefined;
+            var nnz: u32 = undefined;
+            _ = try file.readAll(std.mem.asBytes(&rows));
+            _ = try file.readAll(std.mem.asBytes(&cols));
+            _ = try file.readAll(std.mem.asBytes(&nnz));
+
+            // CSR data
+            const row_ptr = try self.allocator.alloc(u32, rows + 1);
+            const col_idx = try self.allocator.alloc(u16, nnz);
+            const values = try self.allocator.alloc(f16, nnz);
+
+            _ = try file.readAll(std.mem.sliceAsBytes(row_ptr));
+            _ = try file.readAll(std.mem.sliceAsBytes(col_idx));
+            _ = try file.readAll(std.mem.sliceAsBytes(values));
+
+            tensors[i] = TensorCSR{
+                .name = name,
+                .csr = CSRMatrix{
+                    .rows = rows,
+                    .cols = cols,
+                    .nnz = nnz,
+                    .row_ptr = row_ptr,
+                    .col_idx = col_idx,
+                    .values = values,
+                },
+            };
+        }
+
+        return tensors;
+    }
+};
+
+// =============================================================================
+// Main - CLI for hybrid format creation
+// =============================================================================
+
+pub fn main() !void {
+    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
+    defer _ = gpa.deinit();
+    const allocator = gpa.allocator();
+
+    const args = try std.process.argsAlloc(allocator);
+    defer std.process.argsFree(allocator, args);
+
+    if (args.len < 2) {
+        std.debug.print(
+            \\Usage: hybrid-quantizer <model.gguf> [output_dir]
+            \\
+            \\Creates hybrid Q2_K + outlier format for 30 TPS inference.
+            \\Requires outlier profile at <model.gguf>.outliers.bin
+            \\
+            \\Output:
+            \\  <output_dir>/<model>-Q2_K.gguf    - Base model (RAM-resident)
+            \\  <output_dir>/<model>-hybrid.csr  - Sparse outliers
+            \\
+        , .{});
+        return;
+    }
+
+    const model_path = args[1];
+    const output_dir = if (args.len > 2) args[2] else std.fs.path.dirname(model_path) orelse ".";
+
+    // Check for outlier profile
+    const outlier_path = try std.fmt.allocPrint(allocator, "{s}.outliers.bin", .{model_path});
+    defer allocator.free(outlier_path);
+
+    std.fs.cwd().access(outlier_path, .{}) catch {
+        std.debug.print("Error: Outlier profile not found: {s}\n", .{outlier_path});
+        std.debug.print("Run outlier-analyzer first to create it.\n", .{});
+        return;
+    };
+
+    std.debug.print("=== HYBRID QUANTIZER ===\n", .{});
+    std.debug.print("Model: {s}\n", .{model_path});
+    std.debug.print("Outliers: {s}\n", .{outlier_path});
+    std.debug.print("Output: {s}\n\n", .{output_dir});
+
+    var quantizer = HybridQuantizer.init(allocator);
+    var package = try quantizer.createHybrid(model_path, outlier_path, output_dir);
+    defer package.deinit(allocator);
+
+    std.debug.print("\n=== HYBRID PACKAGE READY ===\n", .{});
+    std.debug.print("Q2_K model: {s}\n", .{package.q2k_model_path});
+    std.debug.print("CSR outliers: {s}\n", .{package.csr_outliers_path});
+    std.debug.print("Total size: {d:.2} GB\n", .{@as(f64, @floatFromInt(package.total_size_bytes)) / 1e9});
+    std.debug.print("Expected speedup: {d:.1}x\n", .{package.speedup_factor});
+}

