+//! Outlier Analyzer for Zell v2.0
+//!
+//! Detects top 1% magnitude weights ("outliers") in MoE expert tensors.
+//! These outliers are critical for model quality and will be stored at FP16
+//! while the remaining 99% can be aggressively quantized to Q2_K.
+//!
+//! Algorithm:
+//! 1. Load GGUF tensor metadata
+//! 2. For each MoE expert weight tensor:
+//!    - Dequantize Q4_K → F32
+//!    - Compute histogram of |weight| values
+//!    - Find 99th percentile threshold
+//!    - Extract indices where |weight| > threshold
+//! 3. Save outlier profile to ~/.cache/zell/outliers/{hash}.bin
+
+const std = @import("std");
+const gguf_loader = @import("inference/gguf_loader.zig");
+const types = @import("inference/gguf/types.zig");
+
+const log = std.log.scoped(.outlier_analyzer);
+
+/// Statistics for a single tensor's outliers
+pub const TensorOutlierStats = struct {
+    name: []const u8,
+    shape: [2]u32,
+    original_type: types.GGMLType,
+    total_elements: u64,
+    mean_abs: f32,
+    max_abs: f32,
+    threshold_1pct: f32, // Value at 99th percentile
+    outlier_count: u32,
+    outlier_fraction: f32, // Should be ~0.01
+    // Outlier data (indices + values)
+    outlier_indices: []u32,
+    outlier_values: []f16,
+};
+
+/// Profile containing all tensor outlier statistics
+pub const OutlierProfile = struct {
+    version: u32 = 1,
+    model_hash: []const u8,
+    analyzed_at: i64,
+    total_tensors: u32,
+    total_weights: u64,
+    total_outliers: u64,
+    overall_outlier_fraction: f32,
+    // Size estimates
+    original_size_bytes: u64,
+    base_q2k_size_bytes: u64,
+    outlier_size_bytes: u64,
+    hybrid_size_bytes: u64,
+    size_reduction_pct: f32,
+    // Per-tensor stats
+    tensor_stats: []TensorOutlierStats,
+
+    pub fn deinit(self: *OutlierProfile, allocator: std.mem.Allocator) void {
+        for (self.tensor_stats) |*stat| {
+            allocator.free(stat.outlier_indices);
+            allocator.free(stat.outlier_values);
+        }
+        allocator.free(self.tensor_stats);
+    }
+};
+
+/// Histogram bucket for percentile calculation
+const HISTOGRAM_BUCKETS = 10000;
+
+pub const OutlierAnalyzer = struct {
+    allocator: std.mem.Allocator,
+    loader: *gguf_loader.GGUFLoader,
+
+    pub fn init(allocator: std.mem.Allocator, loader: *gguf_loader.GGUFLoader) OutlierAnalyzer {
+        return .{
+            .allocator = allocator,
+            .loader = loader,
+        };
+    }
+
+    /// Analyze all MoE expert tensors and detect outliers
+    pub fn analyzeExperts(self: *OutlierAnalyzer) !OutlierProfile {
+        log.info("Starting outlier analysis...", .{});
+
+        var tensor_stats = std.ArrayList(TensorOutlierStats).initCapacity(self.allocator, 768) catch unreachable;
+        errdefer tensor_stats.deinit(self.allocator);
+
+        var total_weights: u64 = 0;
+        var total_outliers: u64 = 0;
+        var original_size: u64 = 0;
+
+        // Find all MoE expert weight tensors
+        // Pattern: blk.{layer}.ffn_{gate,up,down}.{expert}.weight
+        const n_layers: u32 = 32; // Mixtral
+        const n_experts: u32 = 8;
+
+        for (0..n_layers) |layer| {
+            for (0..n_experts) |expert| {
+                // Analyze gate, up, down projections
+                inline for ([_][]const u8{ "ffn_gate", "ffn_up", "ffn_down" }) |proj| {
+                    const tensor_name = try std.fmt.allocPrint(
+                        self.allocator,
+                        "blk.{d}.{s}.{d}.weight",
+                        .{ layer, proj, expert },
+                    );
+                    defer self.allocator.free(tensor_name);
+
+                    if (self.loader.getTensor(tensor_name)) |tensor_info| {
+                        const stats = try self.analyzeTensor(tensor_name, tensor_info);
+                        total_weights += stats.total_elements;
+                        total_outliers += stats.outlier_count;
+                        if (self.loader.getTensorOffsetAndSize(tensor_name)) |info_size| {
+                            original_size += info_size.size;
+                        }
+                        try tensor_stats.append(self.allocator, stats);
+                    }
+                }
+            }
+
+            if (layer % 8 == 7) {
+                log.info("Analyzed layers 0-{d} ({d} tensors, {d} outliers)", .{
+                    layer,
+                    tensor_stats.items.len,
+                    total_outliers,
+                });
+            }
+        }
+
+        // Calculate size estimates
+        // Q2_K: 84 bytes per 256 elements = 0.328 bytes/element
+        // FP16 outliers: 2 bytes/element + 4 bytes index = 6 bytes/outlier
+        const base_q2k_size = (total_weights * 84 + 255) / 256;
+        const outlier_size = total_outliers * 6; // 4-byte index + 2-byte value
+        const hybrid_size = base_q2k_size + outlier_size;
+
+        const profile = OutlierProfile{
+            .model_hash = "", // TODO: compute from loader
+            .analyzed_at = std.time.timestamp(),
+            .total_tensors = @intCast(tensor_stats.items.len),
+            .total_weights = total_weights,
+            .total_outliers = total_outliers,
+            .overall_outlier_fraction = @as(f32, @floatFromInt(total_outliers)) /
+                @as(f32, @floatFromInt(total_weights)),
+            .original_size_bytes = original_size,
+            .base_q2k_size_bytes = base_q2k_size,
+            .outlier_size_bytes = outlier_size,
+            .hybrid_size_bytes = hybrid_size,
+            .size_reduction_pct = 100.0 * (1.0 - @as(f32, @floatFromInt(hybrid_size)) /
+                @as(f32, @floatFromInt(original_size))),
+            .tensor_stats = try tensor_stats.toOwnedSlice(self.allocator),
+        };
+
+        log.info("Outlier analysis complete:", .{});
+        log.info("  Total tensors: {d}", .{profile.total_tensors});
+        log.info("  Total weights: {d:.2} M", .{@as(f64, @floatFromInt(profile.total_weights)) / 1e6});
+        log.info("  Total outliers: {d:.2} M ({d:.2}%)", .{
+            @as(f64, @floatFromInt(profile.total_outliers)) / 1e6,
+            profile.overall_outlier_fraction * 100,
+        });
+        log.info("  Original size: {d:.2} GB", .{@as(f64, @floatFromInt(profile.original_size_bytes)) / 1e9});
+        log.info("  Hybrid size: {d:.2} GB ({d:.1}% reduction)", .{
+            @as(f64, @floatFromInt(profile.hybrid_size_bytes)) / 1e9,
+            profile.size_reduction_pct,
+        });
+
+        return profile;
+    }
+
+    /// Analyze a single tensor for outliers
+    fn analyzeTensor(self: *OutlierAnalyzer, name: []const u8, info: types.GGUFTensorInfo) !TensorOutlierStats {
+        const n_elements = info.dimensions[0] * info.dimensions[1];
+
+        // Allocate buffer for dequantized weights
+        const weights = try self.allocator.alloc(f32, n_elements);
+        defer self.allocator.free(weights);
+
+        // Dequantize using public API
+        self.loader.dequantizeToF32(name, weights) catch |err| {
+            log.warn("Failed to dequantize {s}: {s}", .{ name, @errorName(err) });
+            return TensorOutlierStats{
+                .name = try self.allocator.dupe(u8, name),
+                .shape = .{ @intCast(info.dimensions[0]), @intCast(info.dimensions[1]) },
+                .original_type = info.type_,
+                .total_elements = n_elements,
+                .mean_abs = 0,
+                .max_abs = 0,
+                .threshold_1pct = 0,
+                .outlier_count = 0,
+                .outlier_fraction = 0,
+                .outlier_indices = &[_]u32{},
+                .outlier_values = &[_]f16{},
+            };
+        };
+
+        // Compute histogram of absolute values
+        var histogram: [HISTOGRAM_BUCKETS]u64 = [_]u64{0} ** HISTOGRAM_BUCKETS;
+        var max_abs: f32 = 0;
+        var sum_abs: f64 = 0;
+
+        for (weights) |w| {
+            const abs_w = @abs(w);
+            max_abs = @max(max_abs, abs_w);
+            sum_abs += abs_w;
+        }
+
+        const mean_abs: f32 = @floatCast(sum_abs / @as(f64, @floatFromInt(n_elements)));
+
+        // Build histogram
+        const bucket_width = max_abs / @as(f32, HISTOGRAM_BUCKETS);
+        if (bucket_width > 0) {
+            for (weights) |w| {
+                const abs_w = @abs(w);
+                const bucket = @min(
+                    @as(usize, @intFromFloat(abs_w / bucket_width)),
+                    HISTOGRAM_BUCKETS - 1,
+                );
+                histogram[bucket] += 1;
+            }
+        }
+
+        // Find 99th percentile threshold
+        const target_count = n_elements * 99 / 100; // 99% of elements below threshold
+        var cumulative: u64 = 0;
+        var threshold_bucket: usize = 0;
+
+        for (histogram, 0..) |count, i| {
+            cumulative += count;
+            if (cumulative >= target_count) {
+                threshold_bucket = i;
+                break;
+            }
+        }
+
+        const threshold_1pct = @as(f32, @floatFromInt(threshold_bucket)) * bucket_width;
+
+        // Count and collect outliers
+        var outlier_count: u32 = 0;
+        for (weights) |w| {
+            if (@abs(w) > threshold_1pct) {
+                outlier_count += 1;
+            }
+        }
+
+        // Allocate and fill outlier arrays
+        var outlier_indices = try self.allocator.alloc(u32, outlier_count);
+        var outlier_values = try self.allocator.alloc(f16, outlier_count);
+
+        var outlier_idx: u32 = 0;
+        for (weights, 0..) |w, i| {
+            if (@abs(w) > threshold_1pct) {
+                outlier_indices[outlier_idx] = @intCast(i);
+                outlier_values[outlier_idx] = @floatCast(w);
+                outlier_idx += 1;
+            }
+        }
+
+        return TensorOutlierStats{
+            .name = try self.allocator.dupe(u8, name),
+            .shape = .{ @intCast(info.dimensions[0]), @intCast(info.dimensions[1]) },
+            .original_type = info.type_,
+            .total_elements = n_elements,
+            .mean_abs = mean_abs,
+            .max_abs = max_abs,
+            .threshold_1pct = threshold_1pct,
+            .outlier_count = outlier_count,
+            .outlier_fraction = @as(f32, @floatFromInt(outlier_count)) /
+                @as(f32, @floatFromInt(n_elements)),
+            .outlier_indices = outlier_indices,
+            .outlier_values = outlier_values,
+        };
+    }
+
+    /// Save outlier profile to binary file
+    pub fn saveProfile(_: *OutlierAnalyzer, profile: *const OutlierProfile, path: []const u8) !void {
+        const file = try std.fs.cwd().createFile(path, .{});
+        defer file.close();
+
+        // Write header
+        _ = try file.write("ZELL_OUTLIERS");
+        _ = try file.write(std.mem.asBytes(&profile.version));
+        _ = try file.write(std.mem.asBytes(&profile.total_tensors));
+        _ = try file.write(std.mem.asBytes(&profile.total_weights));
+        _ = try file.write(std.mem.asBytes(&profile.total_outliers));
+        _ = try file.write(std.mem.asBytes(&profile.original_size_bytes));
+
+        // Write each tensor's outlier data
+        for (profile.tensor_stats) |stat| {
+            // Name (length-prefixed)
+            const name_len: u16 = @intCast(stat.name.len);
+            _ = try file.write(std.mem.asBytes(&name_len));
+            _ = try file.write(stat.name);
+
+            // Shape
+            _ = try file.write(std.mem.asBytes(&stat.shape[0]));
+            _ = try file.write(std.mem.asBytes(&stat.shape[1]));
+
+            // Stats
+            const type_int: u32 = @intFromEnum(stat.original_type);
+            _ = try file.write(std.mem.asBytes(&type_int));
+            _ = try file.write(std.mem.asBytes(&stat.threshold_1pct));
+            _ = try file.write(std.mem.asBytes(&stat.outlier_count));
+
+            // Outlier data
+            _ = try file.write(std.mem.sliceAsBytes(stat.outlier_indices));
+            _ = try file.write(std.mem.sliceAsBytes(stat.outlier_values));
+        }
+
+        log.info("Saved outlier profile to {s}", .{path});
+    }
+
+    /// Load outlier profile from binary file
+    pub fn loadProfile(allocator: std.mem.Allocator, path: []const u8) !OutlierProfile {
+        const file = try std.fs.cwd().openFile(path, .{});
+        defer file.close();
+
+        // Verify magic
+        var magic: [13]u8 = undefined;
+        _ = try file.readAll(&magic);
+        if (!std.mem.eql(u8, &magic, "ZELL_OUTLIERS")) {
+            return error.InvalidMagic;
+        }
+
+        var version: u32 = undefined;
+        _ = try file.readAll(std.mem.asBytes(&version));
+        var total_tensors: u32 = undefined;
+        _ = try file.readAll(std.mem.asBytes(&total_tensors));
+        var total_weights: u64 = undefined;
+        _ = try file.readAll(std.mem.asBytes(&total_weights));
+        var total_outliers: u64 = undefined;
+        _ = try file.readAll(std.mem.asBytes(&total_outliers));
+        var original_size_bytes: u64 = undefined;
+        _ = try file.readAll(std.mem.asBytes(&original_size_bytes));
+
+        const tensor_stats = try allocator.alloc(TensorOutlierStats, total_tensors);
+
+        for (0..total_tensors) |i| {
+            var name_len: u16 = undefined;
+            _ = try file.readAll(std.mem.asBytes(&name_len));
+            const name = try allocator.alloc(u8, name_len);
+            _ = try file.readAll(name);
+
+            var shape_0: u32 = undefined;
+            var shape_1: u32 = undefined;
+            _ = try file.readAll(std.mem.asBytes(&shape_0));
+            _ = try file.readAll(std.mem.asBytes(&shape_1));
+
+            var type_int: u32 = undefined;
+            _ = try file.readAll(std.mem.asBytes(&type_int));
+            var threshold: f32 = undefined;
+            _ = try file.readAll(std.mem.asBytes(&threshold));
+            var outlier_count: u32 = undefined;
+            _ = try file.readAll(std.mem.asBytes(&outlier_count));
+
+            const indices = try allocator.alloc(u32, outlier_count);
+            _ = try file.readAll(std.mem.sliceAsBytes(indices));
+
+            const values = try allocator.alloc(f16, outlier_count);
+            _ = try file.readAll(std.mem.sliceAsBytes(values));
+
+            tensor_stats[i] = .{
+                .name = name,
+                .shape = .{ shape_0, shape_1 },
+                .original_type = @enumFromInt(type_int),
+                .total_elements = @as(u64, shape_0) * shape_1,
+                .mean_abs = 0, // Not stored
+                .max_abs = 0, // Not stored
+                .threshold_1pct = threshold,
+                .outlier_count = outlier_count,
+                .outlier_fraction = @as(f32, @floatFromInt(outlier_count)) /
+                    @as(f32, @floatFromInt(@as(u64, shape_0) * shape_1)),
+                .outlier_indices = indices,
+                .outlier_values = values,
+            };
+        }
+
+        // Calculate derived fields
+        const base_q2k_size = (total_weights * 84 + 255) / 256;
+        const outlier_size = total_outliers * 6;
+        const hybrid_size = base_q2k_size + outlier_size;
+
+        const size_reduction_pct = if (original_size_bytes > 0)
+            100.0 * (1.0 - @as(f32, @floatFromInt(hybrid_size)) / @as(f32, @floatFromInt(original_size_bytes)))
+        else
+            0;
+
+        return OutlierProfile{
+            .version = version,
+            .model_hash = "",
+            .analyzed_at = 0,
+            .total_tensors = total_tensors,
+            .total_weights = total_weights,
+            .total_outliers = total_outliers,
+            .overall_outlier_fraction = @as(f32, @floatFromInt(total_outliers)) /
+                @as(f32, @floatFromInt(total_weights)),
+            .original_size_bytes = original_size_bytes,
+            .base_q2k_size_bytes = base_q2k_size,
+            .outlier_size_bytes = outlier_size,
+            .hybrid_size_bytes = hybrid_size,
+            .size_reduction_pct = size_reduction_pct,
+            .tensor_stats = tensor_stats,
+        };
+    }
+};
+
+// Test entrypoint
+pub fn main() !void {
+    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
+    defer _ = gpa.deinit();
+    const allocator = gpa.allocator();
+
+    const args = try std.process.argsAlloc(allocator);
+    defer std.process.argsFree(allocator, args);
+
+    if (args.len < 2) {
+        std.debug.print("Usage: {s} <model.gguf>\n", .{args[0]});
+        return error.MissingArgument;
+    }
+
+    const model_path = args[1];
+
+    std.debug.print("\n=== OUTLIER ANALYZER ===\n", .{});
+    std.debug.print("Model: {s}\n\n", .{model_path});
+
+    var loader = try gguf_loader.GGUFLoader.init(allocator, model_path);
+    defer loader.deinit();
+
+    var analyzer = OutlierAnalyzer.init(allocator, &loader);
+    var profile = try analyzer.analyzeExperts();
+    defer profile.deinit(allocator);
+
+    // Print summary
+    std.debug.print("\n=== OUTLIER SUMMARY ===\n", .{});
+    std.debug.print("Tensors analyzed: {d}\n", .{profile.total_tensors});
+    std.debug.print("Total weights: {d:.2} M\n", .{@as(f64, @floatFromInt(profile.total_weights)) / 1e6});
+    std.debug.print("Total outliers: {d:.2} M ({d:.2}%)\n", .{
+        @as(f64, @floatFromInt(profile.total_outliers)) / 1e6,
+        profile.overall_outlier_fraction * 100,
+    });
+    std.debug.print("\nSize estimates:\n", .{});
+    std.debug.print("  Original (Q4_K): {d:.2} GB\n", .{@as(f64, @floatFromInt(profile.original_size_bytes)) / 1e9});
+    std.debug.print("  Base (Q2_K): {d:.2} GB\n", .{@as(f64, @floatFromInt(profile.base_q2k_size_bytes)) / 1e9});
+    std.debug.print("  Outliers (FP16): {d:.2} GB\n", .{@as(f64, @floatFromInt(profile.outlier_size_bytes)) / 1e9});
+    std.debug.print("  Hybrid total: {d:.2} GB\n", .{@as(f64, @floatFromInt(profile.hybrid_size_bytes)) / 1e9});
+    std.debug.print("  Reduction: {d:.1}%\n", .{profile.size_reduction_pct});
+
+    // Save profile
+    const output_path = try std.fmt.allocPrint(allocator, "{s}.outliers.bin", .{model_path});
+    defer allocator.free(output_path);
+    try analyzer.saveProfile(&profile, output_path);
+
+    std.debug.print("\nProfile saved to: {s}\n", .{output_path});
+}
